class Solution:
    def numOfUnplacedFruits(self, fruits, baskets):
        n = len(baskets)
        available = list(range(n))
        unplaced = 0
        for f in fruits:
            chosen = None
            for pos, j in enumerate(available):
                if baskets[j] >= f:
                    chosen = pos
                    break
            if chosen is None:
                unplaced += 1
            else:
                available.pop(chosen)
        return unplaced

